import React, { useState } from "react";
import axios from "axios";
import { WiHumidity, WiStrongWind } from "react-icons/wi";
import { motion } from "framer-motion";

const WeatherUpdate = () => {
    const [city, setCity] = useState("");
    const [weather, setWeather] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const fetchWeather = async () => {
        if (!city) {
            setError("Please enter a city name.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const response = await axios.get(`http://localhost:5000/api/weather/getWeather?city=${city}`);
            setWeather(response.data);
        } catch (err) {
            setError("Failed to fetch weather data.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div 
            style={{ 
                backgroundColor: "#FAEBCD", 
                width: "100vw", 
                height: "100vh", 
                display: "flex", 
                justifyContent: "center", 
                alignItems: "center", 
                position: "relative", // Prevent movement
                overflow: "hidden" // Avoid any scrolling issues
            }}
        >
            <div 
                style={{ 
                    width: "400px", 
                    padding: "20px", 
                    textAlign: "center", 
                    border: "1px solid #ddd", 
                    borderRadius: "15px", 
                    backgroundColor: "#f0f8ff", 
                    boxShadow: "0px 4px 10px rgba(0,0,0,0.2)", 
                    position: "absolute", // Fix in place
                    top: "50%", 
                    left: "50%", 
                    transform: "translate(-50%, -50%)", // Center it perfectly
                    minHeight: "320px" // ✅ Prevents jumping
                }}
            >
                <h2>🌤 Weather Update</h2>
                <input
                    type="text"
                    placeholder="Enter city name"
                    value={city}
                    onChange={(e) => setCity(e.target.value)}
                    style={{ padding: "10px", width: "80%", marginBottom: "10px", borderRadius: "5px", border: "1px solid #ccc" }}
                />
                <br />
                <motion.button 
                    onClick={fetchWeather} 
                    style={{ padding: "10px 20px", border: "none", backgroundColor: "#007bff", color: "white", borderRadius: "5px", cursor: "pointer" }}
                    whileTap={{ scale: 0.9 }} 
                    whileHover={{ scale: 1.05, transition: { duration: 0.2 } }}
                >
                    Get Weather
                </motion.button>

                {loading && <p>Loading...</p>}
                {error && <p style={{ color: "red" }}>{error}</p>}

                {weather && (
                    <motion.div 
                        key={weather.location}
                        initial={{ opacity: 0, y: -10 }} 
                        animate={{ opacity: 1, y: 0 }} 
                        transition={{ type: "spring", stiffness: 100, damping: 10 }} 
                        style={{ 
                            marginTop: "20px", 
                            padding: "10px", 
                            background: "#f8f9fa", 
                            borderRadius: "10px", 
                            boxShadow: "0px 4px 10px rgba(0,0,0,0.2)", 
                            minHeight: "100px" // ✅ Prevents shifting
                        }}
                    >
                        <h3>{weather.location}</h3>
                        <p>🌡 Temperature: {weather.temperature}°C</p>
                        <p><WiHumidity /> Humidity: {weather.humidity}%</p>
                        <p><WiStrongWind /> Wind Speed: {weather.wind_speed} m/s</p>
                        <p>🌦 Condition: {weather.weather}</p>
                    </motion.div>
                )}
            </div>
        </div>
    );
};

export default WeatherUpdate;
